using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9 breaking change #1: discriminator property renamed from "Discriminator" to "$type".
        // Preserve the old property name so existing documents are still found.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // EF Core 9 breaking change #2: id format changed from "{Discriminator}|{Key}" to just "{Key}".
        // Preserve the old id format so existing documents keep working.
        modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);
        modelBuilder.Entity<Blog>().Property(b => b.Id)
            .HasJsonPropertyName("id")
            .ToJsonProperty("id");

        // EF Core 9 breaking change #3: HasIndex() now throws for Cosmos provider.
        // Removed: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // Preserve the EF Core 8 id format: "EntityType|KeyValue"
        configurationBuilder.Conventions.Add(_ =>
            new Microsoft.EntityFrameworkCore.Cosmos.Infrastructure.IdValueGeneratorConvention());
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

